<?php
namespace Tests\Feature;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\CharacterEquipmentSlot;use App\Domain\Equipment\CharacterEquipmentSummaryService;use App\Domain\Equipment\EquipmentType;use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Equipment\Exceptions\InsufficientEquipmentInventoryCapacityException;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Domain\Inventory\Instances\ItemInstanceInventoryPolicy;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\CharacterItem;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Str;use InvalidArgumentException;use RuntimeException;use Tests\TestCase;
class CharacterEquipmentTest extends TestCase{use RefreshDatabase;private $origin=1000;private function player($capacity=30){return Character::factory()->for(User::factory())->create(['base_inventory_slots'=>$capacity]);}private function item($type='weapon',$status='active',$overrides=[]){return Item::create(array_merge(['code'=>'equipment_'.Str::random(12),'name'=>'Equipo','item_type'=>'equipment','equipment_type'=>$type,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>$status],$overrides));}private function itemInstance(Character $character,Item $item,$status='available',$refinement=0){return ItemInstance::create(['uuid'=>(string)Str::uuid(),'character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>$refinement,'status'=>$status,'origin_type'=>'legacy_inventory','origin_id'=>$this->origin++,'origin_unit_index'=>1,'acquired_at'=>now()]);}public function test_slots_and_item_coherence_are_authoritative(){$validator=app(EquippableItemValidator::class);$weapon=$this->item();$this->assertSame('weapon',$validator->assertCompatible($weapon,'main_hand'));foreach([['item_type'=>'equipment','equipment_type'=>null],['item_type'=>'material','equipment_type'=>'weapon'],['item_type'=>'equipment','equipment_type'=>'unknown'],['item_type'=>'equipment','equipment_type'=>'weapon','is_stackable'=>true,'max_stack'=>2]] as $state){$item=$this->item('weapon','active',$state);try{$validator->equipmentType($item);$this->fail();}catch(InvalidArgumentException $e){$this->assertTrue(true);}}$this->expectException(InvalidArgumentException::class);$validator->assertCompatible($weapon,'helmet');}public function test_equip_changes_state_capacity_and_is_idempotent(){$character=$this->player(1);$instance=$this->itemInstance($character,$this->item());$service=app(CharacterEquipmentService::class);$before=app(CharacterInventorySummaryService::class)->snapshot($character)['inventory_status']['current_used_slots'];$first=$service->equip($character,$instance->uuid,'main_hand');$row=CharacterEquipment::first();$updatedAt=$row->updated_at->format('Y-m-d H:i:s.u');$eventCount=ItemInstanceEvent::count();$second=$service->equip($character,$instance->uuid,'main_hand');$this->assertTrue($first->modified());$this->assertFalse($second->modified());$this->assertNull($second->operationUuid());$this->assertSame($updatedAt,$row->fresh()->updated_at->format('Y-m-d H:i:s.u'));$this->assertSame($eventCount,ItemInstanceEvent::count());$this->assertSame('equipped',$instance->fresh()->status);$this->assertSame($before-1,app(CharacterInventorySummaryService::class)->snapshot($character)['inventory_status']['current_used_slots']);}public function test_replace_is_atomic_and_shares_operation_uuid(){$character=$this->player();$old=$this->itemInstance($character,$this->item(), 'available',0);$new=$this->itemInstance($character,$this->item(), 'available',7);$service=app(CharacterEquipmentService::class);$service->equip($character,$old->uuid,'main_hand');$result=$service->equip($character,$new->uuid,'main_hand');$this->assertSame('available',$old->fresh()->status);$this->assertSame('equipped',$new->fresh()->status);$this->assertSame($new->id,(int)CharacterEquipment::first()->item_instance_id);$events=ItemInstanceEvent::where('operation_uuid',$result->operationUuid())->orderBy('id')->get();$this->assertSame([ItemInstanceEventType::UNEQUIPPED,ItemInstanceEventType::EQUIPPED],$events->pluck('event_type')->all());$this->assertSame([['slot'=>'main_hand'],['slot'=>'main_hand']],$events->pluck('metadata')->all());}public function test_full_inventory_can_equip_but_cannot_unequip(){$character=$this->player(2);$stack=Item::create(['code'=>'full_stack','name'=>'Stack','item_type'=>'material','equipment_type'=>null,'rarity'=>'common','is_stackable'=>true,'max_stack'=>2,'status'=>'active']);CharacterItem::create(['character_id'=>$character->id,'item_id'=>$stack->id,'quantity'=>2,'locked_quantity'=>0]);$instance=$this->itemInstance($character,$this->item());$service=app(CharacterEquipmentService::class);$service->equip($character,$instance->uuid,'main_hand');CharacterItem::where('character_id',$character->id)->update(['quantity'=>4]);$this->expectException(InsufficientEquipmentInventoryCapacityException::class);$service->unequip($character,'main_hand');}public function test_one_free_slot_allows_unequip_even_when_hunting_reserve_fails(){$character=$this->player(2);$stack=Item::create(['code'=>'one_free','name'=>'Stack','item_type'=>'material','equipment_type'=>null,'rarity'=>'common','is_stackable'=>true,'max_stack'=>2,'status'=>'active']);CharacterItem::create(['character_id'=>$character->id,'item_id'=>$stack->id,'quantity'=>2,'locked_quantity'=>0]);$instance=$this->itemInstance($character,$this->item(),'equipped');CharacterEquipment::create(['character_id'=>$character->id,'slot'=>'main_hand','item_instance_id'=>$instance->id,'equipped_at'=>now()]);$result=app(CharacterEquipmentService::class)->unequip($character,'main_hand');$this->assertTrue($result->modified());$this->assertSame('available',$instance->fresh()->status);$this->assertSame(0,CharacterEquipment::count());}public function test_empty_unequip_and_foreign_uuid_are_controlled(){$character=$this->player();$empty=app(CharacterEquipmentService::class)->unequip($character,'helmet');$this->assertFalse($empty->modified());$this->assertNull($empty->operationUuid());$foreign=$this->itemInstance($this->player(),$this->item());$this->expectException(\Illuminate\Database\Eloquent\ModelNotFoundException::class);app(CharacterEquipmentService::class)->equip($character,$foreign->uuid,'main_hand');}public function test_inactive_new_item_rejected_but_inactive_old_can_leave(){$character=$this->player();$oldItem=$this->item('weapon','active');$old=$this->itemInstance($character,$oldItem);$new=$this->itemInstance($character,$this->item());$service=app(CharacterEquipmentService::class);$service->equip($character,$old->uuid,'main_hand');$oldItem->update(['status'=>'inactive']);$service->equip($character,$new->uuid,'main_hand');$this->assertSame('available',$old->fresh()->status);$inactive=$this->itemInstance($character,$this->item('weapon','inactive'));$this->expectException(InvalidArgumentException::class);$service->equip($character,$inactive->uuid,'main_hand');}public function test_inconsistent_status_and_rows_are_rejected(){$character=$this->player();$instance=$this->itemInstance($character,$this->item(),'equipped');try{app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$this->fail();}catch(RuntimeException $e){$this->assertTrue(true);}$instance->update(['status'=>'available']);CharacterEquipment::create(['character_id'=>$character->id,'slot'=>'main_hand','item_instance_id'=>$instance->id,'equipped_at'=>now()]);$this->expectException(RuntimeException::class);app(CharacterEquipmentService::class)->unequip($character,'main_hand');}public function test_two_rings_and_no_silent_move(){$character=$this->player();$left=$this->itemInstance($character,$this->item(EquipmentType::RING));$right=$this->itemInstance($character,$this->item(EquipmentType::RING));$service=app(CharacterEquipmentService::class);$service->equip($character,$left->uuid,'ring_left');$service->equip($character,$right->uuid,'ring_right');$this->assertSame(2,CharacterEquipment::count());$this->expectException(InvalidArgumentException::class);$service->equip($character,$left->uuid,'ring_right');}public function test_policy_and_summaries_separate_equipped_from_inventory(){$policy=app(ItemInstanceInventoryPolicy::class);$this->assertTrue($policy->occupiesInventory('available'));$this->assertFalse($policy->occupiesInventory('equipped'));$character=$this->player();$instance=$this->itemInstance($character,$this->item());app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$inventory=app(CharacterInventorySummaryService::class)->snapshot($character);$equipment=app(CharacterEquipmentSummaryService::class)->snapshot($character)->toArray();$this->assertCount(0,$inventory['item_instances']);$this->assertCount(9,$equipment);$this->assertTrue($equipment[0]['occupied']);$this->assertSame($instance->uuid,$equipment[0]['item_instance_uuid']);}public function test_owner_interface_and_authorization(){$this->seed(\Database\Seeders\CharacterLevelRequirementSeeder::class);$character=$this->player();$instance=$this->itemInstance($character,$this->item());$this->actingAs($character->user)->get(route('characters.inventory.index',$character))->assertOk()->assertSee('Equipar: Mano principal');$this->post(route('characters.equipment.equip',$character),['item_instance_uuid'=>$instance->uuid,'slot'=>'main_hand'])->assertRedirect(route('characters.inventory.index',$character));$this->get(route('characters.show',$character))->assertOk()->assertSee('Equipamiento')->assertSee('Equipo +0')->assertSee('Desequipar');$other=User::factory()->create();$this->actingAs($other)->post(route('characters.equipment.unequip',$character),['slot'=>'main_hand'])->assertForbidden();}}

